   254→var listCmd = &cobra.Command{
   255→	Use:     "list",
   256→	Aliases: []string{"ls"},
   257→	Short:   "List all sandboxes",
   258→	RunE: func(cmd *cobra.Command, args []string) error {
   259→		client, err := api.NewClient()
   260→		if err != nil {
   261→			return err
   262→		}
   263→		printServer(client)
   264→
   265→		sandboxes, err := client.ListSandboxes()
   266→		if err != nil {
   267→			return err
   268→		}
   269→
   270→		if len(sandboxes) == 0 {
   271→			fmt.Println("No sandboxes.")
   272→			return nil
   273→		}
   274→
   275→		hasRoute := false
   276→		for _, s := range sandboxes {
   277→			if len(s.Routes) > 0 {
   278→				hasRoute = true
   279→				break
   280→			}
   281→		}
   282→
   283→		w := tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', 0)
   284→		if hasRoute {
   285→			fmt.Fprintln(w, "NAME\tSTATUS\tPORT\tROUTE\tTAILSCALE IP\tIMAGE")
   286→		} else {
   287→			fmt.Fprintln(w, "NAME\tSTATUS\tPORT\tTAILSCALE IP\tIMAGE")
   288→		}
   289→		for _, s := range sandboxes {
   290→			name := s.Name
   291→			if s.Temporary {
   292→				name += " (temp)"
   293→			}
   294→			tsIP := ""
   295→			if s.TailscaleIP != "" {
   296→				tsIP = s.TailscaleIP
   297→			}
   298→			if hasRoute {
   299→				route := ""
   300→				if len(s.Routes) > 0 {
   301→					parts := make([]string, len(s.Routes))
   302→					for i, r := range s.Routes {
   303→						parts[i] = fmt.Sprintf("%s (:%d)", r.URL, r.Port)
   304→					}
   305→					route = strings.Join(parts, ", ")
   306→				}
   307→				fmt.Fprintf(w, "%s\t%s\t%d\t%s\t%s\t%s\n", name, s.Status, s.SSHPort, route, tsIP, s.Image)
   308→			} else {
   309→				fmt.Fprintf(w, "%s\t%s\t%d\t%s\t%s\n", name, s.Status, s.SSHPort, tsIP, s.Image)
   310→			}
   311→		}
   312→		w.Flush()
   313→		return nil
   314→	},
   315→}
