   394→var useCmd = &cobra.Command{
   395→	Use:   "use [name]",
   396→	Short: "Show or set active server/sandbox",
   397→	Long: `Without arguments, shows the current server and active sandbox.
   398→With an argument, switches the active server or sandbox.
   399→
   400→Examples:
   401→  sandcastle use                  # Show current server and sandbox
   402→  sandcastle use my-sandbox       # Set active sandbox
   403→  sandcastle use prod             # Switch to server "prod" (if configured)`,
   404→	Args: cobra.MaximumNArgs(1),
   405→	RunE: func(cmd *cobra.Command, args []string) error {
   406→		cfg, err := config.Load()
   407→		if err != nil {
   408→			return err
   409→		}
   410→
   411→		// No args: list all servers, highlight active
   412→		if len(args) == 0 {
   413→			if len(cfg.Servers) == 0 {
   414→				fmt.Println("No servers configured — run: sandcastle login <url>")
   415→				return nil
   416→			}
   417→
   418→			aliases := make([]string, 0, len(cfg.Servers))
   419→			for alias := range cfg.Servers {
   420→				aliases = append(aliases, alias)
   421→			}
   422→			sort.Strings(aliases)
   423→
   424→			for _, alias := range aliases {
   425→				srv := cfg.Servers[alias]
   426→				if alias == cfg.CurrentServer {
   427→					fmt.Printf("  \033[1m* %-16s\033[0m %s\n", alias, srv.URL)
   428→				} else {
   429→					fmt.Printf("    %-16s %s\n", alias, srv.URL)
   430→				}
   431→			}
   432→
   433→			return nil
   434→		}
   435→
   436→		name := args[0]
   437→
   438→		// Check if name matches a server alias or URL
   439→		if _, ok := cfg.Servers[name]; ok {
   440→			cfg.CurrentServer = name
   441→			if err := config.Save(cfg); err != nil {
   442→				return err
   443→			}
   444→			fmt.Printf("Switched to server %s (%s)\n", name, cfg.Servers[name].URL)
   445→			return nil
   446→		}
   447→
   448→		// Try matching by URL
   449→		for alias, srv := range cfg.Servers {
   450→			if srv.URL == strings.TrimRight(name, "/") {
   451→				cfg.CurrentServer = alias
   452→				if err := config.Save(cfg); err != nil {
   453→					return err
   454→				}
   455→				fmt.Printf("Switched to server %s (%s)\n", alias, srv.URL)
   456→				return nil
   457→			}
   458→		}
   459→
   460→		return fmt.Errorf("server %q not found — run: sandcastle use", name)
   461→	},
   462→}
