   464→var setCmd = &cobra.Command{
   465→	Use:   "set <name> <temp|keep>",
   466→	Short: "Toggle sandbox between temporary and kept",
   467→	Long: `Toggle a sandbox between temporary (auto-remove on exit) and kept.
   468→
   469→  temp   Mark as temporary — will be removed when the CLI session exits
   470→  keep   Mark as kept — will not be auto-removed`,
   471→	Args: cobra.ExactArgs(2),
   472→	RunE: func(cmd *cobra.Command, args []string) error {
   473→		client, err := api.NewClient()
   474→		if err != nil {
   475→			return err
   476→		}
   477→		printServer(client)
   478→
   479→		sandbox, err := findSandboxByName(client, args[0])
   480→		if err != nil {
   481→			return err
   482→		}
   483→
   484→		mode := strings.ToLower(args[1])
   485→		var temp bool
   486→		switch mode {
   487→		case "temp":
   488→			temp = true
   489→		case "keep":
